import java.util.Scanner;
import org.owasp.encoder.Encode;

public class XSSFixedExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        String sanitizedInput = Encode.forHtml(userInput); // Sanitize user input

        String greetingMessage = "Hello, " + sanitizedInput + "!";

        // Properly handle user input by encoding it before outputting to the webpage
        System.out.println("<h1>" + greetingMessage + "</h1>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
